import{_ as a,o as i,c as t,ag as o}from"./chunks/framework.DjqkqlVQ.js";const p=JSON.parse('{"title":"Changelog","description":"","frontmatter":{},"headers":[],"relativePath":"en/mods/sts2-map-enhance/changelog.md","filePath":"en/mods/sts2-map-enhance/changelog.md","lastUpdated":1778341931000}'),l={name:"en/mods/sts2-map-enhance/changelog.md"};function n(r,e,s,d,h,u){return i(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="changelog" tabindex="-1">Changelog <a class="header-anchor" href="#changelog" aria-label="Permalink to &quot;Changelog&quot;">​</a></h1><p>Player-facing release notes for Map Enhance Mod. The project page currently shows version <code>0.6.2</code>; the Nexus Mods notes provided here are organized through <code>v0.6.1</code>.</p><h2 id="v0-6-1" tabindex="-1">v0.6.1 <a class="header-anchor" href="#v0-6-1" aria-label="Permalink to &quot;v0.6.1&quot;">​</a></h2><ul><li>Fixes the multiplayer mixed-install sync issue introduced in <code>v0.6.0</code>.</li></ul><h2 id="v0-6-0" tabindex="-1">v0.6.0 <a class="header-anchor" href="#v0-6-0" aria-label="Permalink to &quot;v0.6.0&quot;">​</a></h2><ul><li>Support customizing the color of the map brush, and support synchronized multiplayer color settings for the same version mod.</li><li>When opening the deck/card list on the map page, automatically hide the floating mini-map and route recommendation panel. Restore them when returning to the map.</li></ul><h2 id="v0-5-0" tabindex="-1">v0.5.0 <a class="header-anchor" href="#v0-5-0" aria-label="Permalink to &quot;v0.5.0&quot;">​</a></h2><ul><li>Added a draggable and position-remembering mini-map.</li><li>Optimized the performance of the map.</li><li>Store the selected route, and the previous selected route can be restored after S&amp;L.</li></ul><h2 id="v0-4-0" tabindex="-1">v0.4.0 <a class="header-anchor" href="#v0-4-0" aria-label="Permalink to &quot;v0.4.0&quot;">​</a></h2><ul><li>Added 6 new UI languages: Japanese, Korean, Traditional Chinese, Russian, Spanish, and Brazilian Portuguese.</li></ul><h2 id="v0-3-2" tabindex="-1">v0.3.2 <a class="header-anchor" href="#v0-3-2" aria-label="Permalink to &quot;v0.3.2&quot;">​</a></h2><ul><li>Improves performance by trimming always-on map UI work.</li><li>Restores the route-analysis panel more reliably after combat returns to the map.</li></ul><h2 id="v0-3-1" tabindex="-1">v0.3.1 <a class="header-anchor" href="#v0-3-1" aria-label="Permalink to &quot;v0.3.1&quot;">​</a></h2><ul><li>Improved the floating interaction experience of the Route Analysis panel.</li><li>Fixed several known issues and improved overall stability.</li></ul><h2 id="v0-3-0" tabindex="-1">v0.3.0 <a class="header-anchor" href="#v0-3-0" aria-label="Permalink to &quot;v0.3.0&quot;">​</a></h2><ul><li>Enhanced the preset system for the route style, adding advanced rating parameters that can be saved along with the preset.</li><li>Improved the detailed description of the ratings, making the meaning of the advanced parameters more intuitive.</li></ul><h2 id="v0-2-2" tabindex="-1">v0.2.2 <a class="header-anchor" href="#v0-2-2" aria-label="Permalink to &quot;v0.2.2&quot;">​</a></h2><ul><li>Fix the issue where the highlighted route no longer appears after reopening the map when it was previously locked.</li><li>Fix the problem where the locked route needs to be clicked again to regain the highlight after returning to the map from a battle.</li><li>Fix the issue where the &quot;Must-Visit Shop&quot; is automatically checked again after being manually unselected, and it reappears on subsequent map refreshes or when returning from a battle.</li></ul><h2 id="v0-2-1" tabindex="-1">v0.2.1 <a class="header-anchor" href="#v0-2-1" aria-label="Permalink to &quot;v0.2.1&quot;">​</a></h2><ul><li>Fix the compatibility issues with the startup process in the current beta version.</li></ul><h2 id="v0-2-0" tabindex="-1">v0.2.0 <a class="header-anchor" href="#v0-2-0" aria-label="Permalink to &quot;v0.2.0&quot;">​</a></h2><ul><li>Added a route analysis and recommendation panel to display and rank candidate paths.</li><li>Added route sorting options based on elites, enemies, rest sites, unknown rooms, and more.</li><li>Introduced quick style presets for fast switching between routing preferences.</li><li>Improved floating map UI and legend integration to reduce visual clutter.</li><li>Added panel collapsing, dragging, and resizing for better usability.</li><li>Improved settings-page copy and interaction flow, with better localization support.</li><li>Expanded logging and troubleshooting support for easier debugging.</li><li>Fixed multiple state-sync, refresh, and UI consistency issues for better stability.</li></ul><h2 id="v0-1-0" tabindex="-1">v0.1.0 <a class="header-anchor" href="#v0-1-0" aria-label="Permalink to &quot;v0.1.0&quot;">​</a></h2><ul><li>Initial release of the map enhancement mod.</li><li>Added map node coloring by room type.</li><li>Added live preview for map color settings in the settings page.</li><li>Added opacity and brightness controls for display customization.</li><li>Added basic config validation to reduce misconfiguration issues.</li><li>Added logging support for easier troubleshooting.</li><li>Added an <code>F8</code> quick toggle to enable or disable the mod in-game.</li></ul>',24)])])}const m=a(l,[["render",n]]);export{p as __pageData,m as default};
